using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xYConstructionPlane());
    if (!sketch)
        return false;

    // Get sketch lines
    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;
    Ptr sketchLines = curves->sketchLines();
    if (!sketchLines)
        return false;

    // Create sketch rectangle
    Ptr startPoint = Point3D::create(0, 0, 0);
    Ptr endPoint = Point3D::create(5.0, 5.0, 0);
    sketchLines->addTwoPointRectangle(startPoint, endPoint);

    // Get two sketch lines
    Ptr sketchLineOne = sketchLines->item(0);
    Ptr sketchLineTwo = sketchLines->item(1);

    // Get the profile
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);

    // Create an extrusion input
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);

    // Define that the extent is a distance extent of 5 cm
    Ptr distance = ValueInput::createByReal(5.0);
    // Set the distance extent
    extInput->setDistanceExtent(false, distance);
    // Set the extrude type to be solid
    extInput->isSolid(true);

    // Create the extrusion
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Create a sketch circle
    Ptr sketchCircles = curves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(8.0, 8.0, 0);
    Ptr sketchCircle = sketchCircles->addByCenterRadius(centerPoint, 3.0);

    // Get the body with the extrude
    Ptr bodies = ext->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);

    // Get a vertex of the body
    Ptr vertices = body->vertices();
    if (!vertices)
        return false;
    Ptr vertex = vertices->item(0);

    // Get three intersect faces
    Ptr vertexFaces = vertex->faces();
    if (!vertexFaces)
        return false;
    Ptr faceOne = vertexFaces->item(0);
    Ptr faceTwo = vertexFaces->item(1);
    Ptr faceThree = vertexFaces->item(2);

    // Create perpendicular construction axis
    Ptr axes = rootComp->constructionAxes();
    if (!axes)
        return false;
    Ptr axisInput = axes->createInput();
    if (!axisInput)
        return false;
    axisInput->setByPerpendicularAtPoint(faceOne, vertex);
    Ptr axis = axes->add(axisInput);

    // Get construction points
    Ptr constructionPoints = rootComp->constructionPoints();
    if (!constructionPoints)
        return false;

    // Create construction point input
    Ptr pointInput = constructionPoints->createInput();
    if (!pointInput)
        return false;

    // Create construction point by two points
    pointInput->setByTwoEdges(sketchLineOne, sketchLineTwo);
    constructionPoints->add(pointInput);

    // Create construction point by three planes
    pointInput->setByThreePlanes(faceOne, faceTwo, faceThree);
    constructionPoints->add(pointInput);

    // Create construction point by edge and plane
    pointInput->setByEdgePlane(axis, faceOne);
    constructionPoints->add(pointInput);

    // Create construction point by center
    pointInput->setByCenter(sketchCircle);
    constructionPoints->add(pointInput);

    // Create construction point by point
    pointInput->setByPoint(vertex);
    Ptr point = constructionPoints->add(pointInput);

    // Get health state of a construction point
    adsk::fusion::FeatureHealthStates health = point->healthState();
    if (health == adsk::fusion::FeatureHealthStates::ErrorFeatureHealthState ||
        health == adsk::fusion::FeatureHealthStates::WarningFeatureHealthState)
    {
        std::string msg = point->errorOrWarningMessage();
    }

    return true;
}
